```int DataTransferOptimised(int* pidst, int* pisrc, unsigned long SizeInBytes)
{
	unsigned long dwNumElements = SizeInBytes / sizeof(int);
	unsigned long dwNumPacks = dwNumElements / (128/(sizeof(int)*8));

	__asm
	{
		pusha;
	begin:
		mov ecx, SizeInBytes;
		mov edi,pidst;
		mov esi, pisrc;
	begina:
		cmp ecx,0;
		jz end;
	body:

		mov ebx, SizeInBytes;
		sub ebx, ecx;

		movdqa xmm1, [esi+ebx];
		movdqa [edi+ebx], xmm1;

	bodya:
		sub ecx, 16;
		jmp begina;
	end:
		popa;
	}

	return 0;
}

#pragma warning(pop)
``` 
